solutionCode:
function canWriteAccount(programId, account) {
  const ownerMatches = account.owner === programId;
  const writable = account.isWritable === true;
  const allowed = ownerMatches && writable;

  return {
    allowed,
    deniedReason: allowed ? null : (ownerMatches ? 'not_writable' : 'wrong_owner'),
  };
}

testCode:
const ok = canWriteAccount('Prog111', { owner: 'Prog111', isWritable: true });
assert(ok.allowed === true, 'expected allowed');
assert(ok.deniedReason === null, 'deniedReason should be null');

const bad1 = canWriteAccount('Prog111', { owner: 'Prog222', isWritable: true });
assert(bad1.allowed === false, 'expected denied');
assert(bad1.deniedReason === 'wrong_owner', 'wrong owner reason expected');

const bad2 = canWriteAccount('Prog111', { owner: 'Prog111', isWritable: false });
assert(bad2.deniedReason === 'not_writable', 'not writable reason expected');
